namespace sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);

public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);

public record Reaction(string Emoji, List<string> Users);

public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly Dictionary<int, List<Message>> _channelMessages;
    private readonly Dictionary<int, List<Message>> _threads;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels =
        [
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and discussions", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic conversations", 5),
        ];

        var now = DateTime.UtcNow;

        _channelMessages = new()
        {
            [1] =
            [
                new(1, 1, "Alice", "Hey everyone! Welcome to the team channel.", now.AddHours(-5), null, [new("👋", ["Bob", "Carol"])]),
                new(2, 1, "Bob", "Thanks Alice! Excited to be here.", now.AddHours(-4), null, []),
                new(3, 1, "Carol", "Has anyone reviewed the new design specs?", now.AddHours(-3), null, [new("👀", ["Alice"])]),
                new(4, 1, "Dave", "I'll take a look this afternoon.", now.AddHours(-2), null, []),
                new(5, 1, "Alice", "Great! Let me know if you have questions.", now.AddMinutes(-45), null, [new("👍", ["Dave", "Carol"])]),
                new(6, 1, "Eve", "Just pushed the latest updates to staging.", now.AddMinutes(-10), null, []),
                new(7, 1, "Bob", "Nice work Eve! The new features look solid.", now.AddMinutes(-5), null, [new("🎉", ["Alice", "Carol", "Dave"]), new("🚀", ["Eve"])]),
            ],
            [2] =
            [
                new(20, 2, "Dave", "Sprint planning tomorrow at 10am.", now.AddHours(-8), null, []),
                new(21, 2, "Alice", "I've updated the CI pipeline config.", now.AddHours(-6), null, [new("👍", ["Dave"])]),
                new(22, 2, "Bob", "Found a bug in the auth module. Working on a fix.", now.AddHours(-3), null, []),
                new(23, 2, "Carol", "Can someone review PR #142?", now.AddMinutes(-30), null, [new("👀", ["Dave"])]),
            ],
            [3] =
            [
                new(30, 3, "Carol", "New mockups for the dashboard are ready.", now.AddHours(-4), null, [new("😍", ["Alice", "Eve"])]),
                new(31, 3, "Eve", "Love the color scheme!", now.AddHours(-3), null, []),
                new(32, 3, "Alice", "Can we adjust the spacing on the sidebar?", now.AddMinutes(-90), null, []),
            ],
            [4] =
            [
                new(40, 4, "Bob", "Anyone up for lunch?", now.AddHours(-2), null, [new("🍕", ["Carol", "Dave"])]),
                new(41, 4, "Dave", "Sure! How about Thai food?", now.AddHours(-1), null, []),
            ],
        };

        _threads = new()
        {
            [3] =
            [
                new(3, 1, "Carol", "Has anyone reviewed the new design specs?", now.AddHours(-3), null, [new("👀", ["Alice"])]),
                new(10, 1, "Dave", "I skimmed through them. Looks good overall.", now.AddHours(-2).AddMinutes(30), 3, []),
                new(11, 1, "Alice", "I had a few comments on the navigation flow.", now.AddHours(-2), 3, []),
                new(12, 1, "Carol", "Thanks! Let's discuss in our 1:1.", now.AddHours(-1).AddMinutes(30), 3, []),
            ],
            [5] =
            [
                new(5, 1, "Alice", "Great! Let me know if you have questions.", now.AddMinutes(-45), null, [new("👍", ["Dave", "Carol"])]),
                new(13, 1, "Dave", "Quick question about the API contracts.", now.AddMinutes(-30), 5, []),
                new(14, 1, "Alice", "Sure, what's up?", now.AddMinutes(-25), 5, []),
            ],
            [22] =
            [
                new(22, 2, "Bob", "Found a bug in the auth module. Working on a fix.", now.AddHours(-3), null, []),
                new(24, 2, "Dave", "Is it the token refresh issue?", now.AddHours(-2).AddMinutes(30), 22, []),
                new(25, 2, "Bob", "Yes exactly. The refresh token was expiring too early.", now.AddHours(-2), 22, []),
            ],
        };
    }

    public Task<List<Channel>> GetChannelsAsync() =>
        Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        if (!_channelMessages.TryGetValue(channelId, out var messages))
            return Task.FromResult(new List<Message>());

        var result = messages
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();

        return Task.FromResult(result);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(
            Interlocked.Increment(ref _nextMessageId),
            channelId, "You", content, DateTime.UtcNow, replyToId, []);

        if (replyToId is null)
        {
            if (_channelMessages.TryGetValue(channelId, out var messages))
                messages.Add(msg);
        }
        else if (_threads.TryGetValue(replyToId.Value, out var thread))
        {
            thread.Add(msg);
        }
        else
        {
            _threads[replyToId.Value] = [msg];
        }

        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        if (_threads.TryGetValue(rootMessageId, out var thread))
            return Task.FromResult(thread.ToList());

        return Task.FromResult(new List<Message>());
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        foreach (var messages in _channelMessages.Values)
        {
            var msg = messages.FirstOrDefault(m => m.Id == messageId);
            if (msg is not null)
            {
                ApplyReaction(msg, emoji);
                return Task.CompletedTask;
            }
        }

        foreach (var thread in _threads.Values)
        {
            var msg = thread.FirstOrDefault(m => m.Id == messageId);
            if (msg is not null)
            {
                ApplyReaction(msg, emoji);
                return Task.CompletedTask;
            }
        }

        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };

        return Task.CompletedTask;
    }

    private static void ApplyReaction(Message msg, string emoji)
    {
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }
}

@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="channel-item @(IsActive ? "active" : "")" role="button" @onclick="OnSelected">
    <div class="d-flex justify-content-between align-items-center">
        <div class="text-truncate me-2">
            <div class="channel-name"># @Channel.Name</div>
            <div class="channel-desc text-truncate">@Channel.Description</div>
        </div>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-primary rounded-pill flex-shrink-0">@Channel.UnreadCount</span>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelected { get; set; }
}

.channel-item {
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    border-radius: 0.375rem;
    margin: 0.125rem 0.5rem;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(0, 0, 0, 0.06);
}

.channel-item.active {
    background-color: rgba(13, 110, 253, 0.12);
    color: #0d6efd;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.channel-desc {
    font-size: 0.75rem;
    color: #6c757d;
}

@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h6 class="mb-0 fw-bold">Channels</h6>
    </div>
    <div class="sidebar-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 1rem;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="message-bubble" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="d-flex justify-content-between align-items-start">
        <div>
            <span class="fw-bold">@Message.Author</span>
            <span class="text-muted small ms-2">@FormatRelativeTime(Message.SentAt)</span>
        </div>
        @if (_showActions)
        {
            <div class="message-actions d-flex gap-1">
                @if (!HideReplyAction)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                        💬 Reply
                    </button>
                }
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        @onclick="ToggleEmojiPicker"
                        @onclick:stopPropagation="true">
                    😀 React
                </button>
            </div>
        }
    </div>

    <div class="mt-1">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="mt-1 d-flex gap-1 flex-wrap">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge"
                      role="button"
                      @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <a href="#" class="thread-link"
           @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)"
           @onclick:preventDefault>
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </a>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <span class="emoji-option"
                      role="button"
                      @onclick="() => SelectEmoji(emoji)">
                    @emoji
                </span>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool HideReplyAction { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

