@page "/chat"
@rendermode InteractiveServer
@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_selectedChannelId"
                    OnChannelSelected="SelectChannelAsync" />

    <div class="message-area">
        @if (_selectedChannel is not null)
        {
            <div class="message-header">
                <h5 class="mb-0"># @_selectedChannel.Name</h5>
                <small class="text-muted">@_selectedChannel.Description</small>
            </div>

            <div class="message-list" @ref="_messageListRef">
                @if (_hasMoreMessages)
                {
                    <div class="text-center py-2">
                        <button class="btn btn-sm btn-outline-secondary"
                                disabled="@_isLoadingMore"
                                @onclick="LoadMoreMessagesAsync">
                            @if (_isLoadingMore)
                            {
                                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            }
                            Load older messages
                        </button>
                    </div>
                }

                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ReplyCount="_replyCounts.GetValueOrDefault(msg.Id)"
                                   OnReplyClicked="OpenThreadAsync"
                                   OnReactionAdded="AddReactionAsync" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{_selectedChannel.Name}")"
                          OnSend="SendMessageAsync" />
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <span>Select a channel to start chatting</span>
            </div>
        }
    </div>

    @if (_activeThreadRootId is not null && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadMessages"
                     OnClose="CloseThread"
                     OnReplySent="SendThreadReplyAsync"
                     OnReactionAdded="AddReactionAsync" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private int? _activeThreadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];
    private Dictionary<int, int> _replyCounts = new();
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;
    private bool _shouldScrollToBottom;
    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;

    private const int PageSize = 20;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
            await SelectChannelAsync(_channels[0].Id);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            try
            {
                _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                    "import", "./Components/Chat/ChatPage.razor.js");
            }
            catch (JSException) { }
        }

        if (_shouldScrollToBottom && _jsModule is not null)
        {
            _shouldScrollToBottom = false;
            try
            {
                await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
            }
            catch (JSException) { }
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages.Clear();
        _replyCounts.Clear();
        _hasMoreMessages = true;
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count >= PageSize;

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();

        await LoadThreadSummariesForAsync(messages);
        _shouldScrollToBottom = true;
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (_selectedChannelId is null || _isLoadingMore) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            await LoadThreadSummariesForAsync(older);
        }

        _hasMoreMessages = older.Count >= PageSize;
        _isLoadingMore = false;
    }

    private async Task LoadThreadSummariesForAsync(List<Message> messages)
    {
        foreach (var msg in messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count(m => m.ReplyToId is not null);
            if (replyCount > 0)
                _replyCounts[msg.Id] = replyCount;
        }
    }

    private async Task SendMessageAsync(string content)
    {
        if (_selectedChannelId is null || string.IsNullOrWhiteSpace(content)) return;

        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
        _shouldScrollToBottom = true;
    }

    private async Task OpenThreadAsync(int messageId)
    {
        _activeThreadRootId = messageId;
        var thread = await ChatService.GetThreadAsync(messageId);
        _threadRootMessage = thread.FirstOrDefault(m => m.ReplyToId is null)
                             ?? _messages.FirstOrDefault(m => m.Id == messageId);
        _threadMessages = thread.Where(m => m.ReplyToId is not null).ToList();
    }

    private void CloseThread()
    {
        _activeThreadRootId = null;
        _threadRootMessage = null;
        _threadMessages.Clear();
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (_activeThreadRootId is null || string.IsNullOrWhiteSpace(content)) return;

        var msg = await ChatService.SendMessageAsync(
            _selectedChannelId!.Value, content, _activeThreadRootId.Value);
        _threadMessages.Add(msg);
        _replyCounts[_activeThreadRootId.Value] = _threadMessages.Count;
    }

    private async Task AddReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh channel messages
        if (_selectedChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(
                _selectedChannelId.Value, 0, _messages.Count);
        }

        // Refresh thread if open
        if (_activeThreadRootId is not null)
        {
            var thread = await ChatService.GetThreadAsync(_activeThreadRootId.Value);
            _threadRootMessage = thread.FirstOrDefault(m => m.ReplyToId is null)
                                 ?? _messages.FirstOrDefault(m => m.Id == _activeThreadRootId);
            _threadMessages = thread.Where(m => m.ReplyToId is not null).ToList();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

