public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly Dictionary<int, List<Message>> _channelMessages;
    private readonly Dictionary<int, List<Message>> _threads;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels =
        [
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and discussions", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic conversations", 5),
