                new(6, 1, "Eve", "Just pushed the latest updates to staging.", now.AddMinutes(-10), null, []),
                new(7, 1, "Bob", "Nice work Eve! The new features look solid.", now.AddMinutes(-5), null, [new("🎉", ["Alice", "Carol", "Dave"]), new("🚀", ["Eve"])]),
            ],
            [2] =
            [
                new(20, 2, "Dave", "Sprint planning tomorrow at 10am.", now.AddHours(-8), null, []),
                new(21, 2, "Alice", "I've updated the CI pipeline config.", now.AddHours(-6), null, [new("👍", ["Dave"])]),
                new(22, 2, "Bob", "Found a bug in the auth module. Working on a fix.", now.AddHours(-3), null, []),
                new(23, 2, "Carol", "Can someone review PR #142?", now.AddMinutes(-30), null, [new("👀", ["Dave"])]),
            ],
            [3] =
            [
                new(30, 3, "Carol", "New mockups for the dashboard are ready.", now.AddHours(-4), null, [new("😍", ["Alice", "Eve"])]),
                new(31, 3, "Eve", "Love the color scheme!", now.AddHours(-3), null, []),
                new(32, 3, "Alice", "Can we adjust the spacing on the sidebar?", now.AddMinutes(-90), null, []),
            ],
            [4] =
            [
                new(40, 4, "Bob", "Anyone up for lunch?", now.AddHours(-2), null, [new("🍕", ["Carol", "Dave"])]),
                new(41, 4, "Dave", "Sure! How about Thai food?", now.AddHours(-1), null, []),
            ],
        };

        _threads = new()
        {
            [3] =
            [
                new(3, 1, "Carol", "Has anyone reviewed the new design specs?", now.AddHours(-3), null, [new("👀", ["Alice"])]),
                new(10, 1, "Dave", "I skimmed through them. Looks good overall.", now.AddHours(-2).AddMinutes(30), 3, []),
                new(11, 1, "Alice", "I had a few comments on the navigation flow.", now.AddHours(-2), 3, []),
                new(12, 1, "Carol", "Thanks! Let's discuss in our 1:1.", now.AddHours(-1).AddMinutes(30), 3, []),
            ],
            [5] =
            [
                new(5, 1, "Alice", "Great! Let me know if you have questions.", now.AddMinutes(-45), null, [new("👍", ["Dave", "Carol"])]),
                new(13, 1, "Dave", "Quick question about the API contracts.", now.AddMinutes(-30), 5, []),
                new(14, 1, "Alice", "Sure, what's up?", now.AddMinutes(-25), 5, []),
            ],
            [22] =
            [
