@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="channel-item @(IsActive ? "active" : "")" role="button" @onclick="OnSelected">
    <div class="d-flex justify-content-between align-items-center">
        <div class="text-truncate me-2">
            <div class="channel-name"># @Channel.Name</div>
            <div class="channel-desc text-truncate">@Channel.Description</div>
        </div>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-primary rounded-pill flex-shrink-0">@Channel.UnreadCount</span>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelected { get; set; }
}

.channel-item {
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    border-radius: 0.375rem;
    margin: 0.125rem 0.5rem;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(0, 0, 0, 0.06);
}

.channel-item.active {
    background-color: rgba(13, 110, 253, 0.12);
    color: #0d6efd;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.channel-desc {
    font-size: 0.75rem;
    color: #6c757d;
}

