toolArgs.file_text:
@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="message-bubble" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="d-flex justify-content-between align-items-start">
        <div>
            <span class="fw-bold">@Message.Author</span>
            <span class="text-muted small ms-2">@FormatRelativeTime(Message.SentAt)</span>
        </div>
        @if (_showActions)
        {
            <div class="message-actions d-flex gap-1">
                @if (!HideReplyAction)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                        💬 Reply
                    </button>
                }
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        @onclick="ToggleEmojiPicker"
                        @onclick:stopPropagation="true">
                    😀 React
                </button>
            </div>
        }
    </div>

    <div class="mt-1">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="mt-1 d-flex gap-1 flex-wrap">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge"
                      role="button"
                      @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <a href="#" class="thread-link"
           @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)"
           @onclick:preventDefault>
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </a>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <span class="emoji-option"
                      role="button"
                      @onclick="() => SelectEmoji(emoji)">
                    @emoji
                </span>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool HideReplyAction { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

