toolArgs.file_text:
.message-bubble {
    padding: 0.5rem 1rem;
    position: relative;
    border-radius: 0.375rem;
    transition: background-color 0.15s;
}

.message-bubble:hover {
    background-color: rgba(0, 0, 0, 0.03);
}

.message-actions {
    flex-shrink: 0;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.125rem 0.5rem;
    font-size: 0.8rem;
    background: #f0f0f0;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e2e2e2;
}

.thread-link {
    display: block;
    font-size: 0.8rem;
    margin-top: 0.25rem;
    text-decoration: none;
    color: #0d6efd;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.emoji-picker {
    position: absolute;
    bottom: 100%;
    right: 0;
    display: flex;
    gap: 0.25rem;
    padding: 0.375rem;
    background: white;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 10;
}

.emoji-option {
    font-size: 1.25rem;
    padding: 0.25rem;
    cursor: pointer;
    border-radius: 0.25rem;
    transition: background-color 0.15s;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

