@using sv_28190ce6f59c4b49a3ef5cf6b70fc7b6.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0 fw-bold">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="OnClose">✕</button>
    </div>

    <div class="thread-root-quote">
        <div class="fw-bold small">@RootMessage.Author</div>
        <div class="small">@RootMessage.Content</div>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <MessageBubble Message="reply"
                           HideReplyAction="true"
                           OnReactionAdded="OnReactionAdded" />
        }

        @if (Replies.Count == 0)
        {
            <div class="text-muted small text-center py-3">No replies yet</div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonLabel="Reply"
                  OnSend="OnReplySent" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySent { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

.thread-panel {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #dee2e6;
    display: flex;
    flex-direction: column;
    background: #fff;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.thread-root-quote {
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    border-left: 3px solid #0d6efd;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

